using System.Text.RegularExpressions;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ────────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesFullPattern()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsExactFormat()
    {
        var result = _formatter.FormatPhoneNumber("8005559999");

        Assert.AreEqual("(800) 555-9999", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ────────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Smith");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithDearAndTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ReturnsExactFormat()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_Throws(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ─────────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlySlugChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!!");

        StringAssert.Matches(result, new Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_DoesNotStartWithHyphen()
    {
        var result = _formatter.GenerateSlug("  --Leading Dashes  ");

        StringAssert.DoesNotMatch(result, new Regex(@"^-"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_DoesNotEndWithHyphen()
    {
        var result = _formatter.GenerateSlug("Trailing Dashes--  ");

        StringAssert.DoesNotMatch(result, new Regex(@"-$"));
    }

    [TestMethod]
    public void GenerateSlug_MixedCase_StartsWithLowercase()
    {
        var result = _formatter.GenerateSlug("MY TITLE");

        StringAssert.StartsWith(result, "my");
    }

    [TestMethod]
    public void GenerateSlug_MultipleSpaces_CollapsesToSingleHyphen()
    {
        var result = _formatter.GenerateSlug("word   another");

        Assert.AreEqual("word-another", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidTitle_Throws(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ───────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_EndsWith2DecimalPlaces()
    {
        var result = _formatter.FormatCurrency(10m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(5.5m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_ReturnsExactFormat()
    {
        var result = _formatter.FormatCurrency(1234.5m, "£");

        Assert.AreEqual("£1234.50", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-42.10m);

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatCurrency_ZeroAmount_ReturnsZeroFormatted()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}

